fun solve(prices: Array<Long>, strategy: Array<Long>, k: Long): Long {
    val n = prices.size
    var originalProfit = 0L
    for (i in 0 until n) {
        originalProfit += strategy[i] * prices[i]
    }

    val m = k / 2
    val array1 = LongArray(n)
    val array2 = LongArray(n)
    for (i in 0 until n) {
        array1[i] = -strategy[i] * prices[i]
        array2[i] = (1 - strategy[i]) * prices[i]
    }

    val prefix1 = LongArray(n + 1)
    val prefix2 = LongArray(n + 1)
    prefix1[0] = 0L
    prefix2[0] = 0L
    for (i in 0 until n) {
        prefix1[i + 1] = prefix1[i] + array1[i]
        prefix2[i + 1] = prefix2[i] + array2[i]
    }

    var maxGain = 0L
    val maxStart = n - k
    for (i in 0 until (maxStart + 1)) {
        val startFirst = i
        val endFirst = i + m - 1
        val startSecond = i + m
        val endSecond = i + k - 1

        val sumFirst = prefix1[endFirst + 1] - prefix1[startFirst]
        val sumSecond = prefix2[endSecond + 1] - prefix2[startSecond]
        val currentGain = sumFirst + sumSecond
        if (currentGain > maxGain) {
            maxGain = currentGain
        }
    }

    return originalProfit + maxGain
}
